/*!
 * 中京個別指導学院 ─ 印刷ウォーターマーク共通モジュール
 * print-watermark.js   設置先: /assets/print-watermark.js
 * ------------------------------------------------------------------
 * 各学習ツールの「印刷用HTML」にロゴ透かしを共通で入れるための関数群。
 * window.ChukyoPrint を公開する（外部依存なし・ロゴはbase64で内蔵）。
 *
 * ◆ 読み込み（各ツールの <head> など、メインの <script> より前）:
 *     <script src="/assets/print-watermark.js"></script>
 *
 * ◆ 使い方A（簡単・推奨）── 完成したHTML文字列に一括注入:
 *     var html = "<!DOCTYPE html> ... </html>";   // 印刷用HTMLを組み立て
 *     html = ChukyoPrint.inject(html);             // <style>と各ページへ自動注入
 *     var w = window.open("", "_blank");
 *     w.document.write(html); w.document.close(); w.print();
 *
 *   ※ inject は .page があれば各ページ中央へ、無ければ <body> 直後へ入れ、
 *     位置決め用の position:relative も自動で補う。
 *
 * ◆ 使い方B（手動）── 文字列を自分で差し込む:
 *     ・<style> 内へ   ChukyoPrint.css()   を入れる
 *     ・各 .page か <body> 直後へ  ChukyoPrint.img()  を入れる
 *     ・透かしを乗せる入れ物に  position:relative  を付ける
 *
 * ◆ 濃さ・大きさの変更（既定: 薄め 0.24 / 幅 93%）:
 *     ChukyoPrint.css({opacity:0.3, width:80})
 *     ChukyoPrint.inject(html, {opacity:0.3, width:80})
 * ------------------------------------------------------------------
 */
(function (global) {
  'use strict';

  // 中京ロゴ（黒背景を透過したアンバー版・240px・base64内蔵）
  var LOGO = 'data:image/png;base64,';

  var DEFAULTS = { opacity: 0.24, width: 93, maxWidth: 225, zIndex: -1 };

  function num(v, d) { return (v === undefined || v === null) ? d : v; }

  // 透かし用CSS（.wm 1ルール）を文字列で返す
  function css(opts) {
    opts = opts || {};
    var op = num(opts.opacity, DEFAULTS.opacity);
    var w  = num(opts.width,    DEFAULTS.width);
    var mw = num(opts.maxWidth, DEFAULTS.maxWidth);
    var z  = num(opts.zIndex,   DEFAULTS.zIndex);
    return '.wm{position:absolute;left:50%;top:50%;transform:translate(-50%,-50%);'
      + 'width:' + w + '%;max-width:' + mw + 'mm;opacity:' + op + ';'
      + 'z-index:' + z + ';pointer-events:none;'
      + '-webkit-print-color-adjust:exact;print-color-adjust:exact;}';
  }

  // 透かし画像タグを文字列で返す
  function img() {
    return '<img class="wm" src="' + LOGO + '" alt="">';
  }

  // 完成済みHTML文字列へ一括注入して返す
  function inject(html, opts) {
    if (typeof html !== 'string') return html;
    var hasPage = /<div class="page"/.test(html);
    var pos = hasPage ? '  .page{position:relative;}\n' : '  body{position:relative;}\n';
    var styleRule = pos + '  ' + css(opts) + '\n';
    if (html.indexOf('</style>') !== -1) {
      html = html.replace('</style>', styleRule + '</style>');
    }
    var image = img();
    if (hasPage) {
      html = html.replace(/(<div class="page"[^>]*>)/g, '$1' + image);
    } else {
      html = html.replace(/<body[^>]*>/, function (m) { return m + image; });
    }
    return html;
  }

  global.ChukyoPrint = {
    LOGO: LOGO, DEFAULTS: DEFAULTS,
    css: css, img: img, inject: inject
  };
})(window);
